syntax = "proto3";

package envoy.extensions.filters.http.custom_header_injection.v3;

import "envoy/config/core/v3/base.proto";
import "udpa/annotations/status.proto";
import "validate/validate.proto";

option java_package = "io.envoyproxy.envoy.extensions.filters.http.custom_header_injection.v3";
option java_outer_classname = "CustomHeaderInjectionProto";
option java_multiple_files = true;
option go_package = "github.com/envoyproxy/go-control-plane/envoy/extensions/filters/http/custom_header_injection/v3;custom_header_injectionv3";
option (udpa.annotations.file_status).package_version_status = ACTIVE;

// [#protodoc-title: Custom Header Injection Filter]
// [#extension: envoy.filters.http.custom_header_injection]

// Configuration for the Custom Header Injection filter.
message CustomHeaderInjection {
  // Headers to add to the request.
  repeated config.core.v3.HeaderValueOption request_headers_to_add = 1;

  // Headers to add to the response.
  repeated config.core.v3.HeaderValueOption response_headers_to_add = 2;
}

#pragma once

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"
#include "envoy/http/filter.h"

#include "source/common/common/logger.h"
#include "source/extensions/filters/http/common/pass_through_filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

using ProtoConfig = envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection;

/**
 * Configuration for the Custom Header Injection filter.
 */
class FilterConfig {
public:
  FilterConfig(const ProtoConfig& config);

  const ProtoConfig& config() const { return config_; }

private:
  const ProtoConfig config_;
};

using FilterConfigSharedPtr = std::shared_ptr<FilterConfig>;

/**
 * Custom Header Injection filter that injects headers into requests and responses.
 */
class CustomHeaderInjectionFilter : public Http::PassThroughFilter,
                                   public Logger::Loggable<Logger::Id::filter> {
public:
  CustomHeaderInjectionFilter(FilterConfigSharedPtr config);

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;

  // Http::StreamEncoderFilter
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;

private:
  const FilterConfigSharedPtr config_;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"
#include "source/common/http/header_utility.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

FilterConfig::FilterConfig(const ProtoConfig& config) : config_(config) {}

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(FilterConfigSharedPtr config)
    : config_(std::move(config)) {}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers,
                                                                    bool) {
  // Inject request headers
  for (const auto& header_to_add : config_->config().request_headers_to_add()) {
    Http::HeaderUtility::addHeader(headers, header_to_add);
  }
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
                                                                    bool) {
  // Inject response headers
  for (const auto& header_to_add : config_->config().response_headers_to_add()) {
    Http::HeaderUtility::addHeader(headers, header_to_add);
  }
  return Http::FilterHeadersStatus::Continue;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

