#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.validate.h"
#include "envoy/registry/registry.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

Http::FilterFactoryCb CustomHeaderInjectionFactory::createFilterFactoryFromProtoTyped(
    const envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection&
        proto_config,
    const std::string&, Server::Configuration::FactoryContext&) {
  auto filter_config = std::make_shared<FilterConfig>(proto_config);

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
  };
}

/**
 * Static registration for the custom header injection filter.
 */
REGISTER_FACTORY(CustomHeaderInjectionFactory, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

