    64→Http::FilterFactoryCb BasicAuthFilterFactory::createFilterFactoryFromProtoTyped(
    65→    const BasicAuth& proto_config, const std::string& stats_prefix,
    66→    Server::Configuration::FactoryContext& context) {
    67→  UserMap users = readHtpasswd(THROW_OR_RETURN_VALUE(
    68→      Config::DataSource::read(proto_config.users(), false, context.serverFactoryContext().api()),
    69→      std::string));
    70→  FilterConfigConstSharedPtr config = std::make_unique<FilterConfig>(
    71→      std::move(users), proto_config.forward_username_header(),
    72→      proto_config.authentication_header(), stats_prefix, context.scope());
    73→  return [config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    74→    callbacks.addStreamDecoderFilter(std::make_shared<BasicAuthFilter>(config));
    75→  };
    76→}
