arguments.new_string:
Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers,
                                                                    bool) {
  // Inject request headers
  for (const auto& header_to_add : config_->config().request_headers_to_add()) {
    addHeader(headers, header_to_add);
  }
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
                                                                    bool) {
  // Inject response headers
  for (const auto& header_to_add : config_->config().response_headers_to_add()) {
    addHeader(headers, header_to_add);
  }
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::addHeader(Http::HeaderMap& headers,
                                           const envoy::config::core::v3::HeaderValueOption& header_to_add) {
  const auto& header_key = Http::LowerCaseString(header_to_add.header().key());
  const auto& header_value = header_to_add.header().value();

  // Skip if the value is empty and we're not supposed to add empty headers
  if (header_value.empty() && !header_to_add.add_if_empty()) {
    return;
  }

  using HeaderAppendAction = envoy::config::core::v3::HeaderValueOption::HeaderAppendAction;
  HeaderAppendAction action = header_to_add.append_action();

  switch (action) {
  case HeaderAppendAction::APPEND_IF_EXISTS_OR_ADD:
    headers.addCopy(header_key, header_value);
    break;
  case HeaderAppendAction::ADD_IF_ABSENT:
    if (headers.get(header_key).empty()) {
      headers.addCopy(header_key, header_value);
    }
    break;
  case HeaderAppendAction::OVERWRITE_IF_EXISTS_OR_ADD:
    headers.setCopy(header_key, header_value);
    break;
  case HeaderAppendAction::OVERWRITE_IF_EXISTS:
    if (!headers.get(header_key).empty()) {
      headers.setCopy(header_key, header_value);
    }
    break;
  default:
    break;
  }
}

